CREATE TABLE `bacaan` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_gerakan` int(11) NOT NULL,
  `urutan` smallint(6) NOT NULL,
  `teks_arab` text NOT NULL,
