INSERT INTO `bacaan` VALUES (1,2,1,'اللهُ أَكْبَرُ','Allahu Akbar','Allah Maha Besar.','Allah Maha Besar.','assets/audio/takbir.mp3','HPT Muhammadiyah'),(2,3,1,'اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ، اللَّهُمَّ نَقِّنِي مِنَ الْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنَ الدَّنَسِ، اللَّهُمَّ اغْسِلْ خَطَايَايَ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ','Allahumma baaid bayni wa bayna khatayaya kama baadta baynal masyriqi wal maghrib. Allahumma naqqini minal khataya kama yunaqqats tsaubul abyadu minad danas. Allahummaghsil khatayaya bil maai wats tsalji wal barad.','Ya Allah, jauhkanlah antara aku dan kesalahan-kesalahanku sebagaimana Engkau menjauhkan antara timur dan barat. Ya Allah, bersihkanlah aku dari kesalahan-kesalahanku sebagaimana dibersihkannya kain yang putih dari kotoran. Ya Allah, cucilah kesalahan-kesalahanku dengan air, salju, dan air es.','Ya Allah, jauhkanlah aku dari segala dosa dan bersihkanlah kesalahanku.','assets/audio/iftitah_full.mp3','HPT Muhammadiyah'),(3,4,1,'بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ . الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ . الرَّحْمَنِ الرَّحِيمِ . مَالِكِ يَوْمِ الدِّينِ . إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ . اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ . صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ','Bismillaahir rahmaanir rahiim. Alhamdu lillaahi rabbil \'aalamiin. Ar-rahmaanir-rahiim. Maaliki yaumid-diin. Iyyaaka na\'budu wa iyyaaka nasta\'iin. Ihdinas-shiraatal-mustaqiim. Shiraathal-ladziina an\'amta \'alaihim ghairil-maghdbuubi \'alaihim walad-dhaalliin.','Dengan nama Allah Yang Maha Pengasih lagi Maha Penyayang. Segala puji bagi Allah, Tuhan seluruh alam. Yang Maha Pengasih, Maha Penyayang. Pemilik hari pembalasan. Hanya kepada Engkaulah kami menyembah dan hanya kepada Engkaulah kami memohon pertolongan. Tunjukkanlah kami jalan yang lurus. (yaitu) jalan orang-orang yang telah Engkau beri nikmat kepadanya; bukan (jalan) mereka yang dimurkai, dan bukan (pula jalan) mereka yang sesat.','Membaca Surat Al-Fatihah.','assets/audio/alfatihah.mp3','HPT Muhammadiyah'),(4,5,1,'سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي','Subhanaka allahumma rabbana wa bihamdika allahummaghfir li','Maha Suci Engkau, ya Allah Tuhan kami, and dengan memuji-Mu ya Allah, ampunilah aku.','Maha Suci Engkau ya Allah, ampunilah dosaku.','assets/audio/rukuk.mp3','HPT Muhammadiyah'),(5,6,1,'سَمِعَ اللهُ لِمَنْ حَمِدَهُ  رَبَّنَا وَلَكَ الْحَمْدُ','Sami\'allahu liman hamidah rabbana wa lakal hamd','Allah Maha Mendengar orang yang memuji-Nya. Ya Tuhan kami, bagi-Mu lah segala puji.','Ya Allah, segala puji bagi-Mu.','assets/audio/itidal_1.mp3','HPT Muhammadiyah'),(6,7,1,'سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي','Subhanaka allahumma rabbana wa bihamdika allahummaghfir li','Maha Suci Engkau, ya Allah Tuhan kami, and dengan memuji-Mu ya Allah, ampunilah aku.','Maha Suci Engkau ya Allah, ampunilah dosaku.','assets/audio/sujud.mp3','HPT Muhammadiyah'),(7,8,1,'اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاجْبُرْنِي وَاهْدِنِي وَارْزُقْنِي','Allahummaghfir li warhamni wajburni wahdini warzuqni','Ya Allah ampunilah aku, rahmatilah aku, cukupkanlah aku, tunjukilah aku, dan berilah aku rezeki.','Ya Allah ampunilah aku dan berilah aku rezeki.','assets/audio/duduk_antara.mp3','HPT Muhammadiyah'),(8,9,1,'سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي','Subhanaka allahumma rabbana wa bihamdika allahummaghfir li','Maha Suci Engkau, ya Allah Tuhan kami, and dengan memuji-Mu ya Allah, ampunilah aku.','Maha Suci Engkau ya Allah, ampunilah dosaku.','assets/audio/sujud.mp3','HPT Muhammadiyah'),(9,10,1,'اللهُ أَكْبَرُ','Allahu Akbar','Allah Maha Besar.','Allah Maha Besar.',NULL,'HPT Muhammadiyah'),(10,11,1,'التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ، السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللهِ وَبَرَكَاتُهُ، السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللهِ الصَّالِحِينَ، أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ','At-tahiyyatu lillah wash-shalawatu wat-thayyibat. Assalamu \'alaika ayyuhan nabiyyu wa rahmatullahi wa barakatuh. Assalamu \'alaina wa \'ala \'ibadillahis shalihin. Asyhadu alla ilaha illallah wa asyhadu anna muhammadan \'abduhu wa rasuluh.','Segala penghormatan, kebahagiaan and kebaikan adalah kepunyaan Allah. Semoga keselamatan, rahmat Allah and berkah-Nya limpah kepadamu wahai Nabi. Semoga keselamatan bagi kami and bagi hamba-hamba Allah yang saleh. Aku bersaksi bahwa tidak ada Tuhan selain Allah and aku bersaksi bahwa Muhammad adalah hamba and utusan-Nya.','Segala puji bagi Allah, salam sejahtera untuk Nabi and hamba yang saleh. Aku bersaksi tiada Tuhan selain Allah and Muhammad utusan-Nya.','assets/audio/tasyahud_awal.mp3','HPT Muhammadiyah'),(11,12,1,'التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ... اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ وَبَارِك|َ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا Bَارَكْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ. اَللّهُمَّ إِنِّى أَعُوْذُبِكَ مِنْ عَذَابِ جَهَنَّمَ، وَمِنْ عَذَابِ الْقَبْرِ، وَمِنْ فِتْنَةِ الْمَحْياَ وَالْمَمَاتِ، وَمِنْ شَرِّ فِتْنَةِ الْمَسِيْحِ الدَّجَّالِ','At-tahiyyatu lillah... Allahumma shalli \'ala muhammadin wa \'ala ali muhammadin kama shallaita \'ala ibrahima wa \'ala ali ibrahima, wa barik \'ala muhammadin wa \'ala ali muhammadin kama barakta \'ala ibrahima wa \'ala ali ibrahima fil \'alamina innaka hamidun majid. Allaahumma innii a’uudzubika min ‘adzaabi jahannam. Wamin ‘adzaabil qobri. Wamin fitnatil mahyaa walmamaati. Wamin syarri fitnatil masiihiddadjaal.','Segala penghormatan bagi Allah... Ya Allah, limpahkanlah rahmat kepada Muhammad and keluarga Muhammad sebagaimana Engkau limpahkan rahmat kepada Ibrahim and keluarga Ibrahim. Dan berkahilah Muhammad and keluarga Muhammad sebagaimana Engkau berkahi Ibrahim and keluarga Ibrahim di seluruh alam semesta, sesungguhnya Engkau Maha Terpuji lagi Maha Mulia. Ya Allah aku berlindung kepada Engkau dari siksa jahannam dan siksa kubur, begitu juga dari fitnah hidup dan mati, serta dari jahatnya fitnah dajjal (pengembara yang dusta).','Membaca doa tasyahud akhir beserta shalawat nabi secara lengkap and sempurna.','assets/audio/tasyahud_akhir.mp3','HPT Muhammadiyah'),(12,13,1,'السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكَاتُهُ','Assalamu \'alaikum wa rahmatullahi wa barakatuh','Semoga keselamatan, rahmat Allah, and berkah-Nya tercurah kepadamu.','Semoga keselamatan and rahmat Allah bersamamu.','assets/audio/salam.mp3','HPT Muhammadiyah'),(13,15,1,'اللهُ أَكْبَرُ','Allahu Akbar','Allah Maha Besar.','Allah Maha Besar.','assets/audio/takbir.mp3','HPT Muhammadiyah'),(14,16,1,'اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ، اللَّهُمَّ نَقِّنِي مِنَ الْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنَ الدَّنَسِ، اللَّهُمَّ اغْسِلْ خَطَايَايَ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ','Allahumma baaid bayni wa bayna khatayaya kama baadta baynal masyriqi wal maghrib. Allahumma naqqini minal khataya kama yunaqqats tsaubul abyadu minad danas. Allahummaghsil khatayaya bil maai wats tsalji wal barad.','Ya Allah, jauhkanlah antara aku and kesalahan-kesalahanku...','Ya Allah, jauhkanlah aku dari segala dosa.','assets/audio/iftitah_full.mp3','HPT Muhammadiyah'),(15,17,1,'بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ . الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ . الرَّحْمَنِ الرَّحِيمِ . مَالِكِ يَوْمِ الدِّينِ . إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ . اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ . صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ','Bismillaahir rahmaanir rahiim. Alhamdu lillaahi rabbil \'aalamiin. Ar-rahmaanir-rahiim. Maaliki yaumid-diin. Iyyaaka na\'budu wa iyyaaka nasta\'iin. Ihdinas-shiraatal-mustaqiim. Shiraathal-ladziina an\'amta \'alaihim ghairil-maghdbuubi \'alaihim walad-dhaalliin.','Dengan nama Allah Yang Maha Pengasih lagi Maha Penyayang. Segala puji bagi Allah, Tuhan seluruh alam. Yang Maha Pengasih, Maha Penyayang. Pemilik hari pembalasan. Hanya kepada Engkaulah kami menyembah dan hanya kepada Engkaulah kami memohon pertolongan. Tunjukkanlah kami jalan yang lurus. (yaitu) jalan orang-orang yang telah Engkau beri nikmat kepadanya; bukan (jalan) mereka yang dimurkai, dan bukan (pula jalan) mereka yang sesat.','Segala puji bagi Allah, Tuhan semesta alam.','assets/audio/alfatihah.mp3','HPT Muhammadiyah'),(16,18,1,'سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي','Subhanaka allahumma rabbana wa bihamdika allahummaghfir li','Maha Suci Engkau, ya Allah Tuhan kami, ampunilah aku.','Maha Suci Engkau ya Allah, ampunilah dosaku.','assets/audio/rukuk.mp3','HPT Muhammadiyah'),(17,19,1,'سَمِعَ اللهُ لِمَنْ حَمِدَهُ . رَبَّنَا وَلَكَ الْحَمْدُ','Sami\'allahu liman hamidah Rabbana wa lakal hamd','Allah Maha Mendengar orang yang memuji-Nya. Ya Tuhan kami, bagi-Mu lah segala puji.','Allah mendengar pujian — Ya Allah, segala puji bagi-Mu.','assets/audio/itidal_1.mp3','HPT Muhammadiyah'),(18,20,1,'سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي','Subhanaka allahumma rabbana wa bihamdika allahummaghfir li','Maha Suci Engkau, ya Allah Tuhan kami, ampunilah aku.','Maha Suci Engkau ya Allah, ampunilah dosaku.','assets/audio/sujud.mp3','HPT Muhammadiyah'),(19,21,1,'اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاجْبُرْنِي وَاهْدِنِي وَارْزُقْنِي','Allahummaghfir li warhamni wajburni wahdini warzuqni','Ya Allah ampunilah aku, rahmatilah aku, cukupkanlah aku, tunjukilah aku, and berilah aku rezeki.','Ya Allah ampunilah aku, rahmatilah aku, cukupkanlah aku, tunjukilah aku, and berilah aku rezeki.','assets/audio/duduk_antara.mp3','HPT Muhammadiyah'),(20,22,1,'سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي','Subhanaka allahumma rabbana wa bihamdika allahummaghfir li','Maha Suci Engkau, ya Allah Tuhan kami, ampunilah aku.','Maha Suci Engkau ya Allah, ampunilah dosaku.','assets/audio/sujud.mp3','HPT Muhammadiyah'),(21,23,1,'اللهُ أَكْبَرُ','Allahu Akbar','Allah Maha Besar.','Allah Maha Besar.','assets/audio/takbir.mp3','HPT Muhammadiyah'),(22,24,1,'التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ، السَّلَامُ عَلَيْكَ أَيُّهَا Nَّبِيُّ وَرَحْمَةُ اللهِ وَبَرَكَاتُهُ، السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللهِ الصَّالِحِينَ، أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ','At-tahiyyatu lillah wash-shalawatu wat-thayyibat. Assalamu \'alaika ayyuhan nabiyyu wa rahmatullahi wa barakatuh. Assalamu \'alaina wa \'ala \'ibadillahis shalihin. Asyhadu alla ilaha illallah wa asyhadu anna muhammadan \'abduhu wa rasuluh.','Segala penghormatan, kebahagiaan and kebaikan adalah kepunyaan Allah...','Segala puji bagi Allah, salam untuk Nabi. Aku bersaksi tiada Tuhan selain Allah dan Muhammad utusan-Nya.','assets/audio/tasyahud_awal.mp3','HPT Muhammadiyah'),(23,25,1,'التَّحِيَّاتُ لِلَّهِ... اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ','At-tahiyyatu lillah... Allahumma shalli \'ala muhammadin wa \'ala ali muhammadin kama shallaita \'ala ibrahima wa \'ala ali ibrahima, wa barik \'ala muhammadin wa \'ala ali muhammadin kama barakta \'ala ibrahima wa \'ala ali ibrahima fil \'alamina innaka hamidun majid.','Segala penghormatan bagi Allah... Ya Allah, limpahkanlah rahmat kepada Muhammad...','Membaca doa tasyahud akhir beserta shalawat nabi secara lengkap.','assets/audio/tasyahud_akhir.mp3','HPT Muhammadiyah'),(24,26,1,'السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكَاتُهُ','Assalamu \'alaikum wa rahmatullahi wa barakatuh','Semoga keselamatan tercurah kepadamu.','Semoga keselamatan dan 